export interface PointsProduct {
  name: string;
  redemptionOrigin?: string;
  convertionFactor?: number;
  minRedemptionValue?: number;
  productCode?: string;
  campaingId?: string;
  conversionFactor?: number;
  icon?: string;
  code?: string;
  origin?: string;
  points?: number;
  action?: string | null;
  campaignId?: string | null;
}

export enum PointsProductsStatus {
  IDLE = 'idle',
  LOADING = 'loading',
  SUCCESS = 'success',
  ERROR = 'error',
}

export interface PointsProductsState {
  products: PointsProduct[];
  status: PointsProductsStatus;
  error?: string;
}

export interface PointsProductsActions {
  setStatus: (status: PointsProductsStatus) => void;
  setProducts: (products: PointsProduct[]) => void;
  setError: (error?: string) => void;
  reset: () => void;
}

export interface PointsProductsApiResponse {
  dados: PointsProduct[];
  status: {
    codigoRetorno: number;
    mensagem: string;
  };
}

export interface FilterOption {
  value: string | number;
  label: string;
}

